<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full d-flex">
                            <h4 v-if="MilestoneID == 0" class="modal-title">{{ $t('Add Payment') }} {{ $t(NewTabName) }}
                            </h4>
                            <h4 v-else-if="MilestoneID > 0" class="modal-title">{{ $t('Edit Payment') }} {{
                                $t(NewTabName) }}</h4>
                            <button type="button" class="close" @click="Cancel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                            <dynamic-form ref="validateManageMilestone" lang="en" :schema="FormSchema" >
                                <template v-slot:tgslot-QuotationNumber="{ data }">
                                    <div class="form-group" v-if="IsShowPercentDiv">
                                        <label for="transactionSize">Project completed(%): <span
                                                style="border: 0; color: #f6931f; font-weight: bold;">{{ progress
                                                }}%</span></label>
                                        <div class="slider-container pt-3 ml-2" @mouseenter="showTooltip = true"
                                            @mouseleave="showTooltip = false">
                                            <VueSlider id="progress" v-model="progress" min="0" max="100"
                                                @input="onProgressSlide" :tooltip="showTooltip ? 'always' : 'none'" />
                                        </div>

                                    </div>
                                    <div class="listing">
                                        <div class="table-responsive">
                                    <table class="table table-bordered mt-0" v-if="!IsShowPercentDiv">
                                        <thead class="thead-bg">
                                            <tr>
                                                <th  v-if="!IsShowMileStoneDiv && !IsShowStageDiv">{{$t('Task')}}</th>
                                                <th  v-else-if="IsShowMileStoneDiv">{{$t(NewTabName)}}</th>
                                                <th  v-else-if="IsShowStageDiv">{{$t('Stage')}}</th>
                                                <th >{{$t('Weightage')}}</th>
                                                <th class="text-center" >Actions</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            <tr v-for="(task, index) in tasks" :key="index">
                                                <td  v-if="!IsShowMileStoneDiv && !IsShowStageDiv">
                                                    <select v-model="task.task"
                                                        :class="{ 'is-invalid': showValidation && !task.task }"
                                                        class="form-control">
                                                        <option value="">Select</option>
                                                        <option v-for="option in taskDDlData" :key="option.value"
                                                            :value="option.value">
                                                            {{ option.name }}
                                                        </option>
                                                    </select>
                                                </td>
                                                <td  v-if="IsShowMileStoneDiv">
                                                    <select v-model="task.task"
                                                        :class="{ 'is-invalid': showValidation && !task.task }"
                                                        class="form-control">
                                                        <option value="">Select</option>
                                                        <option v-for="option in mileStoneDDlData" :key="option.value"
                                                            :value="option.value">
                                                            {{ option.name }}
                                                        </option>
                                                    </select>
                                                </td>

                                                <td  v-if="IsShowStageDiv">
                                                    <select v-model="task.task"
                                                        :class="{ 'is-invalid': showValidation && !task.task }"
                                                        class="form-control">
                                                        <option value="">Select</option>
                                                        <option v-for="option in stageData" :key="option.value"
                                                            :value="option.value">
                                                            {{ option.name }}
                                                        </option>
                                                    </select>
                                                </td>


                                                <td>
                                                    <input type="text" v-model.number="task.weightage"
                                                        @input="validateWeightage(task, $event)"
                                                        @keypress="restrictToNumbers($event)"
                                                        :class="{ 'is-invalid': showValidation && (!task.weightage || task.weightage <= 0) }"
                                                        class="form-control" />
                                                </td>
                                                <td class="text-center">
                                                    <a href="javascript:;" @click="addTask" class="mr-2">
                                                        <em class="round-icon-small fa fa-plus bg-success float-none"></em>
                                                    </a>
                                                    <a href="javascript:;" @click="deleteTask(index)"
                                                        v-if="tasks.length > 1">
                                                        <em class="round-icon-small fa fa-trash bg-danger float-none"></em>
                                                    </a>
                                                </td>
                                            </tr>

                                        </tbody>
                                    </table>
                                    </div></div>
                                </template>
                            </dynamic-form>
                        </div>
                        <div class="col-12">
                             <div class="row flex-row-reverse mt-3 mb-3">
     
                                 <div class="col-lg-6 text-right">
                                     <a v-if="InvoiceButtonVisibility" href="javascript:;"
                                         class="btn btn-success save-btn mr-2" v-on:click="CreateIvoice()" title="Save">
                                         <em class="fa fa-save pr-2"></em>{{ $t('SaveAndCreateInvoice') }}
                                     </a>
                                     <a href="javascript:;" class="btn btn-success save-btn mr-2" v-on:click="SaveData()"
                                         title="Save">
                                         <em class="fa fa-save pr-2"></em>{{ $t('Save') }}
                                     </a>
                                     <a href="javascript:;" class="btn btn-danger" v-on:click="Cancel()" title="Cancel">
                                         <em class="fa fa-close pr-2"></em>{{ $t('Cancel') }}
                                     </a>
                                 </div>
                                 <div class="col-lg-6">
                                     <small class="py-2 mandatory">{{ $t('Mandatory') }}</small>
                                 </div>
                             </div>
                        </div>



                    </div>   
                </div>
            </div>
        </div>
        <AddMilestone :ProjectName="ProjectName" />
    </section>
</template>
<script>
import DataService from '../../services/DataService';
import moment from 'moment';
export default {
    props: {
        ProjectName: {
            type: Object,
            required: true
        },
        MilestoneID: {
            type: Number,
            required: true
        },
        projectId: {
            type: Number
        },
        NewTabName: {
            type: Number,
            required: true
        },
        TabsArray: {
            type: Array
        },
        projectCurrency:{
            type:String
        }
        
    },
    data() {
        return {
            tasks: [{ task: '', weightage: 0, type: 'task' }],
            noRecord: false,
            TotalRecords: 0,
            isLoading: false,
            taskOptions: [],
            progress: 0,
            showTooltip: false,
            MileStoneItem: [],
            MilestoneCode: 'task',
            milestonecode: 'task_mile',
            projectId: 0,
            showValidation: false,
            // mileStoneId:0,
            IsShowMileStoneDiv: false,
            IsShowStageDiv: false,
            startDate: '',
            IsShowTaskDiv: false,
            IsShowPercentDiv: false,
            validationMessages: '',
            dueDate: '',
            FormSchemass: [
                {
                    layoutType: "single",
                    group_name: '',
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Name'),
                            name: "Tag",
                            value: "",
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "TextAreaField",
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",
                            validationRules: { "required": false, max: 4000 },
                            config: {
                                rows: 5
                            }
                        }
                    ]
                }
            ],
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Project Name'),
                            name: "ProjectName",
                            value: this.ProjectName,
                            placeholder: "",
                            validationRules: {
                                "required": true

                            },
                            disabled: true,
                        },
                        {
                            astype: "NumericField",
                            label: this.$t('Milestone Number'),
                            name: "MilestoneNumber",
                            value: "",
                            placeholder: "",
                            validationRules: {
                                "required": true,
                                "regex": /^[0-9]+$/,

                            },
                            disabled: false,
                        },
                        {
                            astype: "TextField",
                            label: this.$t('Milestone Name'),
                            name: "MilestoneName",
                            value: "",
                            placeholder: "Enter Milestone Name",
                            validationRules: {
                                "required": true,
                                "max": 50
                            },
                            disabled: false,
                        },
                        {
                            astype: "DateField",
                            label: this.$t("Due Date"),
                            disabled: false,
                            name: "DueDate",
                            value: new Date(),
                            placeholder: this.$t("StartDate"),
                            validationRules: {
                                required: true,
                            },
                            config: { mode: "date", format: "M/D/YYYY", minDate: '', maxDate: '', onChange: this.checkEndMinDate },
                        },

                        {
                            astype: "NumericField",
                            label: this.$t('Remaining Amount Due()'),
                            name: "RemainingAmountDue",
                            value: "",
                            placeholder: "Enter Remaining Amount Due",
                            validationRules: {
                                "required": true,
                                "regex": /^[a-zA-Z0-9\s]*$/,
                                "max": 20
                            },
                            disabled: false,
                        },
                        {
                            astype: "DateField",
                            label: this.$t("Date Received"),
                            disabled: false,
                            name: "DateReceived",
                            value: new Date(),
                            placeholder: this.$t("StartDate"),
                            validationRules: {
                                required: false,
                            },
                            config: { mode: "date", format: "M/D/YYYY", minDate: '', maxDate: '', },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Status'),
                            name: "Status",
                            value: "1001",
                            placeholder: "",
                            validationRules: {
                                required: true,
                            },
                            config: { options: [] },
                            disabled: false,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Milestone Criteria'),
                            name: "MilestoneCriteria",
                            value: "task",
                            placeholder: "",
                            validationRules: {
                                required: true,
                            },
                            config: { options: [], onChange: this.changeMilestone },
                            disabled: false,
                        }]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SlotField",
                            label: '',
                            name: "QuotationNumber",
                            value: "",
                        },
                        {
                            astype: "TextAreaField",
                            label: this.$t('Description'),
                            name: "Description",
                            disabled: false,
                            value: "",
                            config: {
                                rows: 3
                            },
                            placeholder: this.$t(''),
                            validationRules: {
                                "required": true,
                                max: 2000
                                //"regex": /^[a-zA-Z0-9\s]*$/
                            },
                        }
                    ]
                }
            ],
            CommentSchema: [
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Comment'),
                            name: "Comment",
                            value: "",
                            config: {
                                rows: 3
                            },
                            placeholder: this.$t('Enter Comment'),

                        }
                    ]
                }
            ],
            pageNumber: 1,
            isvalidation: false,
            pageSize: 1000,
            taskDDlData: '',
            mileStoneDDlData: '',
            IsGenrateInvoice: false,
            InvoiceButtonVisibility: false,
            StartDate: '',
            EndDate: '',
            Currency: '',
            projectAmount: 0,
            IndustryType_Name:'',
            stageData:[],
            IsGenerateInvoice:0,
            CompanyId:null,
            PPId:0
        }
    },
    watch: {       
        NewTabName: {
            handler(newTabName) {
                if (newTabName) {
                    this.UpdateFieldsText(newTabName);
                }
            },
            immediate: true
        }
    },
    async created() {
        debugger
        var vm = this;
        vm.PPId = vm.$route.params.projectId != undefined ? vm.$route.params.projectId : vm.projectId;
        vm.Currency = vm.projectCurrency;
        vm.FormSchema[0].Data[4].label = vm.$t('Remaining Amount Due(' + vm.projectCurrency + ')');
        vm.CompanyId= this.GetUserInfo.CompanyId;
        vm.GetMilestoneNumber();
        vm.GetProjectDetails();
        vm.MileStoneDropdown();
        vm.GetStage();
        vm.ProjectOverview();
        vm.GetStatus();
        await vm.GetConfigurationValueForCompanyByKey();
        vm.GetMilestoneCriteria();
        vm.TaskListing();
        setTimeout(function () {
            if (vm.MilestoneID > 0) {
                vm.FetchMileStoneDetails();
            }
        }, 500);
    },
    methods: {
        UpdateFieldsText(newTabName) {
            var vm = this;
            vm.FormSchema.forEach((section) => {
                if (section.Data && Array.isArray(section.Data)) {
                    section.Data.forEach((field) => {
                        if (field.name === 'MilestoneNumber') {
                            field.label = `${this.$t(this.NewTabName)}` + ' ' + 'Number';
                        }
                        else if (field.name === 'MilestoneName') {
                            field.label = `${this.$t(this.NewTabName)}` + ' ' + 'Name';
                        }
                        else if (field.name === 'MilestoneCriteria') {
                            field.label = `${this.$t(this.NewTabName)}` + ' ' + 'Criteria';
                        }
                    });
                }
            });
        },
        validateWeightage(task, event) {
            let value = event.target.value;
            let cleaned = value.replace(/\D/g, '');
            cleaned = cleaned.replace(/^0+/, '');
            task.weightage = cleaned ? Number(cleaned) : null;
            event.target.value = task.weightage !== null ? task.weightage : '';
        },
        restrictToNumbers(event) {
            const charCode = event.charCode || event.keyCode;
            if (
                (charCode < 48 || charCode > 57) &&
                charCode !== 8 &&
                charCode !== 9 &&
                charCode !== 13
            ) {
                event.preventDefault();
            }
        },
        GetProjectDetails: async function () {
            var vm = this;
            var params = `projectId=${vm.PPId}`;
            await DataService.GetProjectDetails(params).then(function (response) {
                if (response.data.result != null && response.data.result != '') {                    
                    vm.IndustryType_Name= response.data.result.PROJECTOVERVIEW[0].IndustryType_Name;
                    if(vm.IndustryType_Name=='Construction' || vm.IndustryType_Name=='Software Development')
                    {
                        vm.TabsArray.push('Task');
                        vm.TabsArray.push('Milestone');
                    }
                }

            });
        },
          
        ProjectOverview: async function () {
            var vm = this;
            var params = `projectId=${vm.PPId}`;
            await DataService.ProjectOverview(params).then(function (response) {
                if (response.data != null > 0) {
                    vm.StartDate = response.data.planneD_START_DATE;
                    vm.EndDate = response.data.planneD_END_DATE;
                    vm.FormSchema[0].Data[3].config.minDate = vm.StartDate;
                    vm.FormSchema[0].Data[3].config.maxDate = vm.EndDate;
                    vm.FormSchema[0].Data[5].config.minDate = vm.StartDate;
                    vm.FormSchema[0].Data[5].config.maxDate = vm.EndDate;
                    vm.FormSchema[0].Data[0].value=response.data.projecT_NAME;
                }
            });
        },
        checkEndMinDate() {
            var vm = this;
            var selectedstartdate = vm.FormSchema[0].Data[3].value;
            vm.FormSchema[0].Data[5].config.minDate = selectedstartdate;
        },

        CreateIvoice() {
            this.IsGenrateInvoice = true;
            this.SaveData();
        },
        async GetConfigurationValueForCompanyByKey() {
            var url = 'key=PMCanSeeProjectFinance'
            var response = await DataService.GetConfigurationValueForCompanyByKey(url);
            response.data === 'yes' ? this.InvoiceButtonVisibility = true : this.InvoiceButtonVisibility = false;
        },
        FetchMileStoneDetails: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `mileStoneId=${vm.MilestoneID}`;
            DataService.GetMilestoneDetails(url).then((response) => {
                if (response.status === 200) {                    
                    const data = response.data?.result?.data;
                    if (Array.isArray(data) && data.length > 0) {
                        const milestone = data[0];
                        const proj = milestone.PROJ?.[0];
                        const tskTyp = proj?.TSKTYP?.[0];
                        const chList = tskTyp?.CH;
                        if (Array.isArray(chList)) {
                            vm.mileStoneDDlData = chList.map((item) => ({
                                name: item.CHILD_MILESTONE_NAME,
                                value: item.CHILD_ID,
                                weightage: item.WEIGHTAGE
                            }));

                            vm.tasks = chList.map((item) => ({
                                task: item.CHILD_ID,
                                weightage: item.WEIGHTAGE
                            }));
                        }                        
                        vm.$refs.validateManageMilestone.updateProperty("MilestoneNumber", "value", milestone.MILESTONE_NUMBER || '');
                        vm.$refs.validateManageMilestone.updateProperty("MilestoneName", "value", milestone.MILESTONE_NAME.trim() || '');
                        vm.$refs.validateManageMilestone.updateProperty("DueDate", "value", milestone.DUE_DATE || '');
                        vm.$refs.validateManageMilestone.updateProperty("RemainingAmountDue", "value", milestone.AMOUNT_DUE || '');
                        vm.$refs.validateManageMilestone.updateProperty("DateReceived", "value", milestone.DATE_RECEIVED || '');
                        vm.$refs.validateManageMilestone.updateProperty("Status", "value", milestone.STATUS_ID || '');
                        vm.$refs.validateManageMilestone.updateProperty("Description", "value", milestone.MILESTONE_DESC || '');
                        vm.$refs.validateManageMilestone.updateProperty("MilestoneCriteria", "value", response.data.result.data[0].PROJ[0].MILESTONE_CODE || ''); vm.FormSchema[0].Data[7].value = response.data.result.data[0].PROJ[0].MILESTONE_CODE;
                        if (response.data.result.data[0].PROJ[0].MILESTONE_CODE == 'task') {
                            vm.IsShowPercentDiv = false;
                            vm.IsShowMileStoneDiv = false;
                            vm.milestonecode = 'task_mile';
                        }
                        else if (response.data.result.data[0].PROJ[0].MILESTONE_CODE == 'mile') {
                            vm.IsShowPercentDiv = false;
                            vm.IsShowStageDiv=false;
                            vm.IsShowMileStoneDiv = true;
                            vm.milestonecode = 'mile_mile';
                        }
                          else if (response.data.result.data[0].PROJ[0].MILESTONE_CODE == 'stage') {
                            vm.IsShowPercentDiv = false;
                            vm.IsShowMileStoneDiv = false;
                            vm.IsShowStageDiv=true
                            vm.milestonecode = 'stage_stage_comp';
                        }
                        else {
                            vm.milestonecode = 'perc_proj_comp';
                            vm.IsShowPercentDiv = true;
                            vm.progress = response.data.result.data[0].PROJ[0].TSKTYP[0].CH[0].WEIGHTAGE;
                        }
                    }
                }
                vm.isLoading = false;
            });
        },
        addTask() {
            this.tasks.push({ task: '', weightage: 0, type: 'task' });
        },
        onProgressSlide() {
            var vm = this;
            vm.progress = this.progress;
        },
        GetStatus: function () {
            var vm = this;
            var url = `langCode=en&companyId=${vm.CompanyId}&statusType=Project&hasGlobal=true`
            DataService.StatusListing(url).then(response => {
                if (response.status == 200) {
                    if (response.data.result.data != undefined || response.data.result.data != null) {
                        if (response.data.result.data.length > 0) {
                            response.data.result.data.forEach((element) => {
                                var obj = {
                                    value: element.STATUS_ID,
                                    name: element.STATUS
                                }
                                vm.FormSchema[0].Data[6].config.options.push(obj);
                                vm.$refs.validateManageMilestone.UpdateKeyValue();
                            })
                        }
                    }
                }
            })
        },
        deleteTask(index) {
            if (this.tasks.length > 1) {
                this.tasks.splice(index, 1);
            } else {
                this.ShowAlert(this.$t('Cannot delete the last remaining task.'), "warning", true, this.$t("Alert"));
            }
        },        
        AddNewMileStoneItem: function () {
            var vm = this;
            var objmilestoneItem = {
                ddlmilestone: '',
                milestoneWeightage: '',
                type: 'milestone'
            };
            vm.MileStoneItem.push(objmilestoneItem);
            var index = vm.MileStoneItem.length - 1;
        },
        changeMilestone: function (event) {
            debugger
            var vm = this;
            vm.MileStoneItem = [];
            vm.TaskItem = [];
            vm.tasks = [{ task: '', weightage: 0, type: selectedval }];
            var selectedval = event.target.value;
            if (selectedval === "task") {
                vm.AddNewTaskItem();
                vm.TaskListing();
                vm.IsShowTaskDiv = true;
                vm.IsShowMileStoneDiv = false;
                vm.IsShowPercentDiv = false;
                vm.IsShowStageDiv=false;
                vm.milestonecode = 'task_mile';
            }
            else if (selectedval === "mile") {
                 vm.AddNewMileStoneItem();
                vm.MileStoneDropdown();
                vm.IsShowTaskDiv = false;
                vm.IsShowMileStoneDiv = true;
                vm.IsShowPercentDiv = false;
                vm.IsShowStageDiv=false;
                vm.milestonecode = 'mile_mile';                
            }
            else if (selectedval === "stage") {
                 vm.AddNewStageStoneItem();
                vm.GetStage();
                vm.IsShowTaskDiv = false;
                vm.IsShowMileStoneDiv = false;
                vm.IsShowPercentDiv = false;
                vm.IsShowStageDiv=true;
                vm.milestonecode = 'stage_stage_comp';                
            }
            else if (selectedval === "perc") {
                vm.IsShowTaskDiv = false;
                vm.IsShowMileStoneDiv = false;
                vm.IsShowStageDiv=false;
                vm.IsShowPercentDiv = true;
                vm.milestonecode = 'perc_proj_comp';
            }            
            else {
                vm.IsShowTaskDiv = true;
                vm.IsShowMileStoneDiv = false;
                vm.IsShowPercentDiv = false;
                vm.IsShowStageDiv=false;
                vm.AddNewTaskItem();
                vm.AddNewMileStoneItem();
            }
        },
        AddNewTaskItem: function () {
            var vm = this;
            var objtaskItem = {
                ddltask: '',
                taskWeightage: '',
                type: 'task'
            };
            vm.TaskItem.push(objtaskItem);
            var index = vm.TaskItem.length - 1;
        },
        AddNewMileStoneItem: function () {
            var vm = this;
            var objtaskItem = {
                ddltask: '',
                mileWeightage: '',
                type: 'mile'
            };
            vm.TaskItem.push(objtaskItem);
            var index = vm.TaskItem.length - 1;
        }, 
        AddNewStageStoneItem(){
            var vm = this;
            var objtaskItem = {
                ddltask: '',
                mileWeightage: '',
                type: 'stage'
            };
            vm.TaskItem.push(objtaskItem);
            var index = vm.TaskItem.length - 1;
        },       
        GetMilestoneNumber: function () {
            var ths = this;
            var url = `projectId=${ths.PPId}`;
            DataService.GetMilestoneNumber(url).then((response) => {
                if (response.status == 200) {
                    ths.$refs.validateManageMilestone.updateProperty("MilestoneNumber", "value", response.data.result);
                    ths.$refs.validateManageMilestone.UpdateKeyValue();
                }
            })

        },
        // TaskListing: function () {
        //     debugger
        //     var ths = this;
        //     var url = `projectId=${ths.PPId}&pageSize=${ths.pageSize}&pageNumber=${ths.pageNumber}&milestoneid=${ths.MilestoneID}`;
        //     DataService.GetProjectTaskListingByProjectId(url).then((response) => {
        //         if (response.status == 200) {
        //             if (response.data.result.DATA.length > 0) {
        //                 response.data.result.DATA.forEach((element) => {
        //                     var obj = {
        //                         value: element.PROJECT_NAME,
        //                         name: element.TASK_NAME
        //                     }
        //                     this.taskDDlData = response.data.result.DATA.map((element) => ({
        //                         value: element.TASK_ID,
        //                         name: element.TASK_NAME
        //                     }));
        //                 })
        //             }
        //         }
        //     })
        // },
        TaskListing: function () {
            debugger
            var ths = this;
            var url = `id=${ths.PPId}&moduleName=PROJECT&type=PROJECT_TASK&search=&refId=`;
            DataService.GetDDLData(url).then((response) => {
                if (response.status == 200) {
                    if (response.data.DATA.length > 0) {
                        response.data.DATA.forEach((element) => {
                            var obj = {
                                value: element.PROJECT_NAME,
                                name: element.TASK_NAME
                            }
                            ths.taskDDlData = response.data.DATA.map((element) => ({
                                value:  element.value,
                                name: element.name
                            }));
                        })
                    }
                }
            })
        },
        MileStoneDropdown: function (chartElement, chartElementId,ProjectId) {
            var ths = this;
            ths.mileStoneDDlData = [];
            var url = `projectId=${ths.PPId}`;
            DataService.GetMilestoneListingForDDL(url).then((response) => {
                if (response.status == 200) {
                    if (response.data.result.data.length > 0) {
                        debugger
                         response.data.result.data.map((element) => {
                            var obj = {
                                value: element.MILESTONE_ID,
                                name: element.MILESTONE_NAME
                            }
                            ths.mileStoneDDlData = response.data.result.data.map((element) => ({
                                value: element.MILESTONE_ID,
                                name: element.MILESTONE_NAME
                            }));
                        });
                    }
                }
            })
        },                  
         GetStage() {
            var vm = this;
            var url = `id=${vm.PPId}&moduleName=PROJECT&type=PROJECT_PROJECT_STAGE&search=&refId=`;
            DataService.GetDDLData(url).then((response) => {                
                if (response.status == 200) {
                    debugger
                    if (response.data.DATA != undefined || response.data.DATA != null) {                        
                        if (response.data.DATA.length > 0) {
                           response.data.DATA.map((element) => {
                            var obj = {
                                value: element.value,
                                name: element.name
                            }
                            if(response.data.DATA.length>0){
                                 vm.stageData = response.data.DATA.map((element) => ({
                                    value:  element.value,
                                    name: element.name
                                }));
                            }
                        });
                        }
                    }
                }
            })
        }, 
        AddNewMileStoneItem: function () {
            var vm = this;
            var objmilestoneItem = {
                ddlmilestone: '',
                milestoneWeightage: '',
                type: 'milestone'
            };
            vm.MileStoneItem.push(objmilestoneItem);
            var index = vm.MileStoneItem.length - 1;            
        },
        GetMilestoneCriteria() {            
            var ths = this;
            var url = `projectId=${ths.PPId}`;
            DataService.GetMilestoneCriteriaListForDDL(url).then((response) => {
                if (response.status == 200) {
                    if (response.data.result.data != undefined || response.data.result.data != null) {
                        if (response.data.result.data.length > 0) {                            
                            response.data.result.data.forEach((element) => {                                
                                var obj = {
                                    value: element.CODE,
                                    name: ths.$t(element.CODE === 'task' ? (ths.TabsArray.includes('Task') ? element.MILESTONE_TYPE : ths.TabsArray[2])
                                    : element.CODE === 'mile'
                                    ? (ths.TabsArray.includes('Milestone') ? element.MILESTONE_TYPE : ths.TabsArray[4] )
                                   : element.CODE === 'stage' ? (ths.TabsArray.includes('Stage') ? element.MILESTONE_TYPE : ths.TabsArray[11] )
                                    : 'Percentage')}
                                ths.FormSchema[0].Data[7].config.options.push(obj);
                                ths.$refs.validateManageMilestone.UpdateKeyValue();

                            })
                        }
                    }
                }
            })
        },
        CloseAssociate() {
            var vm = this;
            vm.$parent.IsAssociateShow = false;
        },
        SaveData() {   
            
            var vm = this;
            vm.$refs.validateManageMilestone.validateForm.validate().then(result => {
                if (!result) return;                
                var milestoneNumber = vm.FormSchema[0].Data[1].value;
                var milestoneName = vm.FormSchema[0].Data[2].value.trim();
                var dueDate = vm.ConvertDateFormat(vm.FormSchema[0].Data[3].value);
                var amountDue = vm.FormSchema[0].Data[4].value;
                var dateRecieved = vm.ConvertDateFormat(vm.FormSchema[0].Data[5].value);
                var status = vm.FormSchema[0].Data[6].value;
                var milestoneCriteria = vm.FormSchema[0].Data[7].value;
                var milestoneDescription = vm.MilestoneDescription !== ""
                    ? vm.FormSchema[1].Data[1].value.split("'").join("''")
                    : vm.FormSchema[1].Data[1].value;
                var data = {
                    ProjectId: vm.$route.params.projectId ?? this.PPId,
                    MilestoneNumber: milestoneNumber,
                    MilestoneName: milestoneName,
                    DueDate: dueDate,
                    AmountDue: amountDue,
                    DateReceived: dateRecieved,
                    Status: status,
                    MilestoneCriteria: milestoneCriteria,
                    MilestoneDescription: milestoneDescription,
                    milestoneCode: vm.milestonecode,
                    milestoneId: vm.MilestoneID,
                    childItems: []
                };
                if (milestoneCriteria === 'task' || milestoneCriteria === 'mile' || milestoneCriteria === 'stage') {
                    let hasError = false;
                    let errorMessages = [];
                    vm.showValidation = true;
                    vm.tasks.forEach((item, index) => {
                        const label = milestoneCriteria === 'task' ? vm.$t('Task') : milestoneCriteria === 'mile' ?  vm.$t('Milestone') : vm.$t('Stage');
                        if (!item.task || item.task === '' || item.weightage === null || item.weightage === '' || isNaN(item.weightage) || item.weightage <= 0) {
                            hasError = true;
                        }
                    });
                    if (hasError) {
                        vm.ShowAlert(vm.$t('FieldsHighlightedRedAreRequired'), "warning", true, vm.$t("Alert"));
                        return;
                    }
                    vm.tasks.forEach((item) => {
                        data.childItems.push({
                            childId: item.task,
                            childWeightage: item.weightage,
                            childType: milestoneCriteria === 'task' ? 'task' :  milestoneCriteria ==='mile'? 'milestone' : 'stage',
                        });
                    });
                    const uniqueItems = new Set();
                    for (let i = 0; i < data.childItems.length; i++) {
                        const id = data.childItems[i].childId;
                        if (uniqueItems.has(id)) {
                            vm.ShowAlert(vm.$t('Duplicate task cannot be selected From Task'), "warning", true, vm.$t("Alert"));
                            return;
                        }
                        uniqueItems.add(id);
                    }
                }
                if (milestoneCriteria === 'perc') {
                    data.childItems.push({
                        childId: vm.$route.params.projectId,
                        childWeightage: vm.progress,
                        childType: 'project',
                    });
                }
                vm.ChkTotalWeightage = false;
                let totalWeightage = 0;

                if (milestoneCriteria === 'task' || milestoneCriteria === 'mile' || milestoneCriteria === 'stage') {
                    data.childItems.forEach(item => {
                        totalWeightage += parseFloat(item.childWeightage || 0);
                    });
                    if (totalWeightage > 100) {
                        vm.ChkTotalWeightage = true;
                        vm.ShowAlert(vm.$t('TotalWeightageRange'), "failure", true, vm.$t("Alert"));
                        return;
                    }
                }
                if (!vm.ChkTotalWeightage || milestoneCriteria === 'perc') {
                    DataService.SaveMilestone(JSON.stringify(data)).then((response) => {
                        if (response.data.status === 'Success') {
                            if (response.data.result === '0') {
                                vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                            }
                           else if (response.data.result === "-2") {
                                vm.ShowAlert(vm.$t('AddedError', [vm.$t(vm.NewTabName)]), "failure", true, vm.$t("Alert"));
                            }
                            else {
                                if (vm.MilestoneID == 0) {
                                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t(vm.NewTabName)]), "success", true, vm.$t("Alert"));
                                } else {
                                    vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t(vm.NewTabName)]), "success", true, vm.$t("Alert"));
                                }
                                vm.$parent.FetchTaskList();
                                vm.Cancel();
                            }
                        }
                    });
                }
            });
        },
        Cancel() {
            this.$parent.MilestoneListingSchema = false;
        },
        ConvertDateFormat: function (value) {
            return moment(value).format('MM/DD/YYYY');
        },
    }
};

</script>


