<template>
<div> 
    <loader :is-visible="isLoading"></loader>       
    <div class="booking-anchor" v-if="item && (item.StartDate || item.startDate)">     
        <div v-if="item.type === 'M'"
             class="booking"
             style="border:none;background:none;"
             @mouseover="showTooltip = true"
             @mouseleave="showTooltip = false" 
             @click="onBarClick">
            <div class="RpadMap_milestone"></div>
            <div class="label daily" style="top: 0px; padding-left: 0px;">
                <div class="rmtooltipdata mstone" v-show="showTooltip">
                    <div class="rmtooltipinner" :data-type="'Milestone'">
                        <div class="RMheading text-truncate">{{ item.Name || item.name || 'Milestone' }}</div>
                        <div class="RMcontent"></div>
                        <div class="RMcontentdt">{{ formatDate(item.StartDate || item.startDate) }} to {{ formatDate(item.EndDate || item.endDate) }}</div>
                    </div>
                     <div class="arrow"></div>
                </div>
            </div>
        </div>  
        <div v-else-if="item.type === 'T'"
              :class="getBarClass()"                
              @click="onBarClick"    
               :style="getBarStyle(item.type)"          
              @mouseover="showTooltip = true"
              @mouseleave="showTooltip = false">
            <div class="label daily" style="top: 8px; padding-left: 0px;">
                <span style="display: inline-block; white-space: nowrap; text-overflow: ellipsis; max-width: 100%; overflow: hidden; pointer-events: none;">
                    {{ item.Name || item.name }}
                </span>
            </div>
        </div>    
      
        <div v-if="item.type === 'PROJECT'"
              :class="getBarClass()"
              :style="getBarStyle(item.type)"
              :data-days="daysBetween"
              @click="onBarClick"
              @mouseover="showTooltip = true"
              @mouseleave="showTooltip = false">
            <div class="label daily" style="top: 0px; float: left; position: relative; left: 5px; white-space: nowrap; text-overflow: ellipsis; max-width: 94%; overflow: hidden;">
                {{ item.Name || item.name }}
            </div>
        </div>
        <div v-else-if="item.type === 'S' || item.type === 'P'"
              :class="getBarClass()"
              :style="getBarStyle(item.type)"
              :data-days="daysBetween"
              @click="onBarClick"
              @mouseover="showTooltip = true"
              @mouseleave="showTooltip = false">
            <div class="label daily" style="top: 0px; float: left; position: relative; left: 5px; white-space: nowrap; text-overflow: ellipsis; max-width: 94%; overflow: hidden;">
                {{ item.Name || item.name }}
            </div>
            <!-- Calculated end date indicator (if applicable) -->
            <div v-if="daysDiff && daysDiff > 0 && regType !== 'Res'" 
                 class="calculated_enddate text-truncate" 
                 :data-days="daysDiff"
                 :style="getCalculatedEndDateStyle()">
                <div class="label daily" style="top: 0px; padding-left: 0px; position: relative; color: #fff;">
                    {{ daysDiff }} D
                </div>
            </div>
            <div v-else-if="daysDiff && daysDiff > 0 && regType === 'Res'"
                 class="calculated_enddate text-truncate"
                 :data-days="daysDiff"
                 :style="getCalculatedEndDateStyle()">
                <div class="label daily" style="top: 0px; padding-left: 0px; position: relative; color: #fff;">
                    Resigned(Please assign tasks to some other resources)
                </div>
            </div>
        </div>
        <div class="rmtooltipdata" v-if="(item.Type || item.type) !== 'M'" v-show="showTooltip">
            <div class="rmtooltipinner">
                <div class="RMheading text-truncate">{{ item.Name || item.name }}</div>
                <div class="RMcontent" v-if="item.type === 'PROJECT'">
                    <strong>Project ID:</strong> {{ item.projectId || 'N/A' }}<br>
                </div>
                <div class="RMcontentdt">{{ formatDate(item.startDate) }} to {{ formatDate(item.endDate) }}</div>
            </div>
            <div class="arrow"></div>
        </div>
        
        
    </div>
    <div class="my-popups" v-if="showDetail">
            <div class="modal d-block">                
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                      
                        <div class="modal-header theme-primary partition-full d-flex">
                            <h4 class="modal-title">{{ $t('Description') }}</h4>                            
                            <button type="button" class="close" @click="showDetail=false">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                      <div class="modal-body">
                        <div class="row" v-if="detailData && detailData.length > 0">
                     
                            <div class="col-md-6 col-lg-4">
                                <div class="d-none">                        
                                    {{GetType=detailData[0].type=='P' ? 'Phase' : detailData[0].type=='S' ? 'Stage' : detailData[0].type=='M' ? 'MileStone': detailData[0].type=='T'? 'Task' :'Project'}} 
                                </div>
                                <div class="form-group"> 
                                    <label :title="detailData[0].name"><b>{{ GetType }} {{ $t('Title') }}: </b>{{ TruncateStr(detailData[0].name,30) }}</label>
                                </div>
                            </div>
                            <div class="col-md-6 col-lg-4">
                                <div class="form-group"> 
                                    <label :title="formatDate(detailData[0].startDate)"><b>{{ GetType }} {{ $t('Pri_StartDate') }}: </b>{{ formatDate(detailData[0].startDate) }}</label>
                                </div>
                            </div>
                            <div class="col-md-6 col-lg-4">
                                <div class="form-group"> 
                                    <label :title="formatDate(detailData[0].endDate)"><b>{{ GetType }} {{ $t('EventEndDate') }}: </b>{{ formatDate(detailData[0].endDate) }}</label>
                                </div>
                            </div>
                            <div style="position: absolute;right: 30px; " v-if="GetType=='Task' || GetType =='MileStone'">
                                <a href="javascript:;" @click="Editdetail(detailData[0])" class="pullright smallediticon margintop5 milestoneEdit" data-currency="null" data-projectid="119913" data-projectname="Smart" data-pkid="31435">
                                    <i class="fa fa-pencil-square-o text-success font-20"></i>
                                </a>
                            </div>
                        </div>               
                        <div v-else class="text-center">
                            <span class="text-danger">No record found</span>
                        </div>
                </div>                  
                    </div>
                </div>
            </div>
        </div>      
        <div v-if="isStgae">
          <AddNewStage  :EditStageData="stageEditData" @CloseStageModel="CloseModel"/>
        </div> 
        <div v-if="MilestoneListingSchema">
          <AddMilestone  :ProjectName="project.projectName"  :MilestoneID="item.pkId" :projectId="project.projectId" />
        </div>  
</div>
</template>

<script>
import moment from 'moment';
import AddNewStage from '../Stage/AddNewStage.vue';
import AddMilestone from '../../../components/Modal/AddMilestone.vue';
export default {
    name: 'RoadMapBar',
    components:{AddNewStage,AddMilestone},
    data() {
        return {
            isStgae:false,
            isLoading:false,
            MilestoneListingSchema:false,
            isPhase:false,
            showTooltip: false,
            showDetail:false,
            detailData:[],
            stageEditData:[],
            projectdata:{project_id:0},
            GetType:'',
            name:'',
            id:0,
        };
    },
    props: {
        item: {
            type: Object,
            required: true
        },
        day: {
            type: Date,
            required: true
        },
        fromDate: {
            type: Date,
            required: true
        },
        toDate: {
            type: Date,
            required: true
        },
        activeZoom: {
            type: String,
            default: 'Week'
        },
        type: {
            type: String,
            default: 'Week'
        },
        setting: {
            type: String,
            required: true
        },
        projectId: {
            type: [Number, String],
            required: true
        },
        currency: {
            type: String,
            default: ''
        },
        project:{
            type: Object
        },
        calculatedEndDate: {
            type: Date,
            default: null
        },
        calculatedLeaveDays: {
            type: Number,
            default: 0
        },
        totalOffDays: {
            type: Number,
            default: 0
        },
        regType: {
            type: String,
            default: ''
        },
        isResource: {
            type: Boolean,
            default: false
        },
        isMilestone: {
            type: Boolean,
            default: false
        },
        daysDiff: {
            type: Number,
            default: 0
        },
        daysBetweenProp: {
            type: Number,
            default: null
        },
        taskProjectId: {
            type: [Number, String],
            default: null
        },
        taskId: {
            type: [Number, String],
            default: null
        },
        taskIsoCode: {
            type: String,
            default: ''
        }
    },
    computed: {
        plotWidth() {
            // Match column widths used by RoadMapResourceData.getColumnWidth()
            // and RoadMapTimePeriod.getSubPeriodStyle() so bars align with cells
            switch(this.activeZoom) {
                case 'Week':
                    return 65; // Day columns in week view
                case 'Month':
                    return 103.125; // Week columns in month view
                case 'Quarter':
                    return 275; // Month columns in quarter view
                case 'Year':
                    return 206.25; // Quarter columns in year view
                default:
                    return 65;
            }
        },
        startDate() {           
            // Check both camelCase and PascalCase
            const startDateValue = this.item.StartDate || this.item.startDate;
            return this.parseDate(new Date(startDateValue * 1000));
        },
        endDate() {           
            // Check both camelCase and PascalCase
            const endDateValue = this.item.EndDate || this.item.endDate;
            return this.parseDate(new Date(endDateValue * 1000));
        },
        daysBetween() {           
            // Use daysBetweenProp if provided (from parent component calculation)
            if (this.daysBetweenProp !== null && this.daysBetweenProp !== undefined) {
                return this.daysBetweenProp;
            }
            
            if (!this.startDate || !this.endDate) return 1;
            
            // For week view, calculate based on actual days (matching original logic)
            // Original code uses daysBetweenDates for width calculation
            const start = new Date(Math.max(this.startDate.getTime(), this.fromDate.getTime()));
            const end = new Date(Math.min(this.endDate.getTime(), this.toDate.getTime()));
            let days = this.daysBetweenDates(start, end);
            
            // Add calculated leave days if present (matching original logic)
            if (this.calculatedLeaveDays && this.calculatedLeaveDays > 0) {
                days = days + this.calculatedLeaveDays;
            }
            
            return Math.max(days, 1);
        },
        marginLeft() {
            if (!this.startDate) return 0;
            const periodStart = new Date(this.day);
            periodStart.setHours(0, 0, 0, 0);
            const start = new Date(this.startDate);
            start.setHours(0, 0, 0, 0);
            
            if (start < periodStart) return 0;
            
            // Calculate margin based on zoom level and new structure
            switch(this.activeZoom) {
                case 'Week':
                    // Week view: day-by-day columns, so calculate days
                    const weekDays = this.daysBetweenDates(periodStart, start);
                    return Math.max(0, (weekDays - 1) * this.plotWidth);
                    
                case 'Month':
                    // Month view: week-by-week columns, so calculate weeks
                    const monthWeeks = this.weeksBetweenDates(periodStart, start);
                    return Math.max(0, (monthWeeks - 1) * this.plotWidth);
                    
                case 'Quarter':
                    // Quarter view: month-by-month columns, so calculate months
                    const quarterMonths = this.monthsBetweenDates(periodStart, start);
                    return Math.max(0, (quarterMonths - 1) * this.plotWidth);
                    
                case 'Year':
                    // Year view: quarter-by-quarter columns, so calculate quarters
                    const yearQuarters = this.quartersBetweenDates(periodStart, start);
                    return Math.max(0, (yearQuarters - 1) * this.plotWidth);
                    
                default:
                    const diffDefault = this.daysBetweenDates(periodStart, start);
                    return Math.max(0, (diffDefault - 1) * this.plotWidth);
            }
        }
    }, 
    methods: {
        CloseModel()
        {
         this.isStgae=false;
        },
        FetchTaskList(){
          this.$parent.callbackfunction();
          this.$root.$emit('call-SearchRoadMapCall', { action: 'update',ProjectId:this.project.projectId});
        },
        Editdetail(data)
        {    
            this.sLoading=true;  
            if( data.type=='S')   
            {
                var obj={
                    STAGE_NAME:data.name,
                    STAGE_ID:data.pkId,
                    STAGE_TYPE:'Project',
                    STATUS_ID:data.status_id,
                    STAGE_DESC:data.desc,
                    STATUS_ID:1001
                }
                this.stageEditData=obj;
            }    
           this.projectdata.project_id=this.project.projectId;
           this.projectdata.task_id=data.pkId;             
            data.type == 'T' ? this.isTask = true :
            data.type == 'S' ? this.isStgae = true :
            data.type == 'P' ? this.isPhase = true :
            data.type == 'M' ? this.MilestoneListingSchema = true :
            false;

            this.showDetail=false;
            if(this.isTask)
                {
                    this.$parent.editask(this.projectdata,this.item);
                } 
                this.sLoading=false;         
        },
        parseDate(dateValue) {
            if (!dateValue) return null;
            if (dateValue instanceof Date) return dateValue;
            if (typeof dateValue === 'number') {
                return dateValue.toString().length >= 13 
                    ? new Date(dateValue) 
                    : new Date(dateValue * 1000);
            }
            if (typeof dateValue === 'string') {
                return new Date(dateValue);
            }
            return null;
        },
        daysBetweenDates(start, end) {
            const oneDay = 24 * 60 * 60 * 1000;
            const firstDate = new Date(start);
            firstDate.setHours(0, 0, 0, 0);
            const secondDate = new Date(end);
            secondDate.setHours(0, 0, 0, 0);
            return Math.round(Math.abs((firstDate.getTime() - secondDate.getTime()) / oneDay)) + 1;
        },
        weeksBetweenDates(start, end) {
            if (!start || !end) return 0;
            const startDate = new Date(start);
            const endDate = new Date(end);
            startDate.setHours(0, 0, 0, 0);
            endDate.setHours(0, 0, 0, 0);
            
            // Get first day of week for start date
            const dayOfWeek = startDate.getDay();
            const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
            const weekStart = new Date(startDate);
            weekStart.setDate(startDate.getDate() + diffToMonday);
            weekStart.setHours(0, 0, 0, 0);
            
            let weekCount = 0;
            let currentWeek = new Date(weekStart);
            
            while (currentWeek <= endDate) {
                weekCount++;
                currentWeek.setDate(currentWeek.getDate() + 7);
            }
            
            return Math.max(weekCount, 1);
        },
        monthsBetweenDates(start, end) {
            if (!start || !end) return 0;
            const startDate = new Date(start);
            const endDate = new Date(end);
            startDate.setHours(0, 0, 0, 0);
            endDate.setHours(0, 0, 0, 0);
            
            const yearDiff = endDate.getFullYear() - startDate.getFullYear();
            const monthDiff = endDate.getMonth() - startDate.getMonth();
            return Math.max(yearDiff * 12 + monthDiff + 1, 1);
        },
        quartersBetweenDates(start, end) {
            if (!start || !end) return 0;
            const startDate = new Date(start);
            const endDate = new Date(end);
            startDate.setHours(0, 0, 0, 0);
            endDate.setHours(0, 0, 0, 0);
            
            const startQuarter = Math.floor(startDate.getMonth() / 3);
            const endQuarter = Math.floor(endDate.getMonth() / 3);
            const yearDiff = endDate.getFullYear() - startDate.getFullYear();
            return Math.max(yearDiff * 4 + (endQuarter - startQuarter) + 1, 1);
        },
        calculatePeriodsBetween(startDate, endDate, periodType) {
            if (!startDate || !endDate) return 0;
            
            const start = new Date(startDate);
            const end = new Date(endDate);
            start.setHours(0, 0, 0, 0);
            end.setHours(0, 0, 0, 0);
            
            switch(periodType) {
                case 'week':
                    // Calculate number of weeks
                    let weekCount = 0;
                    let currentWeek = new Date(start);
                    const dayOfWeek = currentWeek.getDay();
                    const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
                    currentWeek.setDate(currentWeek.getDate() + diffToMonday);
                    currentWeek.setHours(0, 0, 0, 0);
                    
                    while (currentWeek <= end) {
                        weekCount++;
                        currentWeek.setDate(currentWeek.getDate() + 7);
                    }
                    return Math.max(weekCount, 1);
                    
                case 'month':
                    // Calculate number of months
                    let monthCount = 0;
                    let currentMonth = new Date(start.getFullYear(), start.getMonth(), 1);
                    
                    while (currentMonth <= end) {
                        monthCount++;
                        currentMonth.setMonth(currentMonth.getMonth() + 1);
                    }
                    return Math.max(monthCount, 1);
                    
                case 'year':
                    // Calculate number of years
                    let yearCount = 0;
                    let currentYear = new Date(start.getFullYear(), 0, 1);
                    
                    while (currentYear <= end) {
                        yearCount++;
                        currentYear.setFullYear(currentYear.getFullYear() + 1);
                    }
                    return Math.max(yearCount, 1);
                    
                default:
                    return 1;
            }
        },
        formatDate(dateValue) {
            if (!dateValue) return '';

            let date;

            // If value is numeric or numeric string
            if (!isNaN(dateValue)) {
                dateValue = dateValue.toString();

                // If timestamp is in seconds (10 digits) → convert to milliseconds
                date = dateValue.length === 10 
                    ? new Date(parseInt(dateValue) * 1000) 
                    : new Date(parseInt(dateValue));
            } else {
                // For normal date strings
                date = new Date(dateValue);
            }
            if (isNaN(date.getTime())) return '';

            return moment(date).format('MM/DD/YYYY');
        },
        getBarClass() {
            let baseClass = 'booking mine sticky ui-resizable';            
            if (this.item.type === 'PROJECT' || this.setting === 'PROJECT') {
                baseClass += ' RS_draggable_box1 projectData';
            } else if (this.setting === 'TM') {
                const statusClass = this.getTaskStatusClass();
                const parentId = this.item.ParentId || this.item.parentId || 0;
                if (parentId > 0) {
                    baseClass += ' RS_draggable_box3 TaskData ' + statusClass;
                } else {
                    baseClass += ' RS_draggable_box2 TaskData ' + statusClass;
                }
            } else if (this.setting === 'P') {
                baseClass += ' RS_draggable_box1 phaseData';
            } else if (this.setting === 'S') {
                baseClass += ' RS_draggable_box1 stageData';
            }
            
            return baseClass;
        },
        getTaskStatusClass() {
            const statusCode = (this.item.StatusCode || this.item.statusCode || '').toString();
            switch(statusCode) {
                case 'ACT':
                    return 'taskActive';
                case 'PCAN':
                    return 'taskCancelled';
                case 'PCLSD':
                    return 'taskClosed';
                case 'STATUS_DONE':
                    return 'taskCompleted';
                case 'INACT':
                    return 'taskInactive';
                case 'PNPGRS':
                    return 'taskInprogress';
                case 'REFPEN':
                    return 'taskpending';
                default:
                    return '';
            }
        },
        getBarStyle(type) {            
            if (!this.startDate || !this.endDate) {
                return {
                    display: 'none'
                };
            }            
            // For PROJECT type, ensure it spans the full date range as a long continuous strip
            if (type === 'PROJECT' || this.item.type === 'PROJECT' || this.setting === 'PROJECT') {
                // Use actual project dates for width calculation (not clipped to visible range)
                const projectStart = new Date(this.startDate);
                const projectEnd = new Date(this.endDate);
                projectStart.setHours(0, 0, 0, 0);
                projectEnd.setHours(23, 59, 59, 999);                
                // For positioning, use dates clipped to visible range
                const visibleStart = new Date(Math.max(projectStart.getTime(), this.fromDate.getTime()));
                const visibleEnd = new Date(Math.min(projectEnd.getTime(), this.toDate.getTime()));                
                // Calculate the start position relative to the period where bar is rendered
                // this.day is the first date of the period where the project starts
                const periodStart = new Date(this.day);
                periodStart.setHours(0, 0, 0, 0);                
                // Calculate margin from period start to visible start
                // This positions the bar correctly within the period cell
                let marginLeft = 0;
                if (visibleStart.getTime() > periodStart.getTime()) {
                    switch(this.activeZoom) {                        
                        case 'Week': {
                            debugger
                            // In week view, each period is a single day
                            const daysDiff = this.daysBetweenDates(periodStart, visibleStart);
                            marginLeft = (daysDiff - 1) * this.plotWidth;
                            break;
                        }
                        case 'Month': {
                            // In month view, each period is a week
                            const weeksDiff = this.weeksBetweenDates(periodStart, visibleStart);
                            marginLeft = (weeksDiff - 1) * this.plotWidth;
                            break;
                        }
                        case 'Quarter': {
                            // In quarter view, each period is a month
                            const monthsDiff = this.monthsBetweenDates(periodStart, visibleStart);
                            marginLeft = (monthsDiff - 1) * this.plotWidth;
                            break;
                        }
                        case 'Year': {
                            // In year view, each period is a quarter
                            const quartersDiff = this.quartersBetweenDates(periodStart, visibleStart);
                            marginLeft = (quartersDiff - 1) * this.plotWidth;
                            break;
                        }
                    }
                }
                marginLeft = Math.max(0, marginLeft);
                
                // Calculate total width from visible start to visible end
                // This ensures the bar spans the full visible duration of the project
                let width = 0;
                switch(this.activeZoom) {                    
                    case 'Week': {
                        debugger
                        // Calculate days from visible start to visible end (inclusive)
                        const visibleDays = this.daysBetweenDates(visibleStart, visibleEnd);
                        // Width should span all days in the visible range
                        width = visibleDays * this.plotWidth;
                        break;
                    }
                    case 'Month': {
                        // Calculate weeks from visible start to visible end
                        const visibleWeeks = this.weeksBetweenDates(visibleStart, visibleEnd);
                        width = visibleWeeks * this.plotWidth;
                        break;
                    }
                    case 'Quarter': {
                        // Calculate months from visible start to visible end
                        const visibleMonths = this.monthsBetweenDates(visibleStart, visibleEnd);
                        width = visibleMonths * this.plotWidth;
                        break;
                    }
                    case 'Year': {
                        // Calculate quarters from visible start to visible end
                        const visibleQuarters = this.quartersBetweenDates(visibleStart, visibleEnd);
                        width = visibleQuarters * this.plotWidth;
                        break;
                    }
                    default:
                        width = this.daysBetween * this.plotWidth;
                }                
                // Ensure minimum width of at least one cell
                width = Math.max(width, this.plotWidth);                
                return {
                    width: width + 'px',
                    marginLeft: marginLeft + 'px',
                    position: 'absolute',
                    left: '0px',
                    minWidth: this.plotWidth + 'px',
                    height: '30px',
                    zIndex: 20,
                    borderRadius: '3px'
                };
            }
            
            // Calculate width based on new structure for other types
            let width = 0;
            const start = new Date(Math.max(this.startDate.getTime(), this.fromDate.getTime()));
            const end = new Date(Math.min(this.endDate.getTime(), this.toDate.getTime()));
            
            switch(this.activeZoom) {
                case 'Week':
                    // Week view: width = days * 30px
                    const weekDays = this.daysBetweenDates(start, end);
                    width = weekDays * this.plotWidth;
                    // Special handling: subtract 31 if width > 31 (matching original)
                    // if (width > 31) {
                    //     width = width - 31;
                    // }
                    break;
                    
                case 'Month':
                    // Month view: width = weeks * 80px
                    const monthWeeks = this.weeksBetweenDates(start, end);
                    width = monthWeeks * this.plotWidth;
                    break;
                    
                case 'Quarter':
                    // Quarter view: width = months * 100px
                    const quarterMonths = this.monthsBetweenDates(start, end);
                    width = quarterMonths * this.plotWidth;
                    break;
                    
                case 'Year':
                    // Year view: width = quarters * 120px
                    const yearQuarters = this.quartersBetweenDates(start, end);
                    width = yearQuarters * this.plotWidth;
                    break;
                    
                default:
                    width = this.daysBetween * this.plotWidth;
            }
            
            
            const finalWidth = Math.max(width, this.plotWidth);
            debugger
            return {
                width: finalWidth + 'px',
                position: 'relative',
                float: 'left',
                minWidth: this.plotWidth + 'px',
                zIndex: 20
            };
        },
        getItemType() {
            const itemType = this.item.Type || this.item.type;
            if (itemType === 'M') return 'Milestone';
            if (this.setting === 'TM') return 'Task';
            if (this.setting === 'P') return 'Phase';
            if (this.setting === 'S') return 'Stage';
            return 'Task';
        },
        getCalculatedEndDateStyle() {
            if (!this.daysDiff || this.daysDiff <= 0) return { display: 'none' };
            const width = this.daysDiff * this.plotWidth;
            return {
                position: 'absolute',
                width: width + 'px',
                zIndex: 20
            };
        },
        onBarClick() {
             this.isLoading=true;         
            this.detailData=Array(this.item);
            this.showDetail=true;
            this.isLoading=false;       
        }
    }
}
</script>

