<template>
    <div class="roadmap daily" :class="{ detailed: activeZoom === 'Day', months: activeZoom === 'Month', years: activeZoom === 'Year' }" id="calendar">
        <div class="pullleft clsroadmap">
            <RoadMapSidebar :roadMapData="roadMapData" :selectedSettings="selectedSettings" :activeZoom="activeZoom" />
            <section class="rm_cal">
                <header>
                    <RoadMapTimePeriod :fromDate="fromDate" :toDate="toDate" :activeZoom="activeZoom" />
                </header>
                <div id="resourcesmaindata">
                    <div v-for="(project, index) in roadMapData" :key="index" id="resources" class="divresources">
                        <RoadMapResourceData :project="project" :fromDate="fromDate" :toDate="toDate" 
                            :activeZoom="activeZoom" :selectedSettings="selectedSettings" />
                    </div>
                </div>
            </section>
        </div>
    </div>
</template>

<script>
import RoadMapSidebar from './RoadMapSidebar.vue';
import RoadMapTimePeriod from './RoadMapTimePeriod.vue';
import RoadMapResourceData from './RoadMapResourceData.vue';

export default {
    name: 'RoadMapCalendar',
    components: {
        RoadMapSidebar,
        RoadMapTimePeriod,
        RoadMapResourceData
    },
    props: {
        roadMapData: {
            type: Array,
            default: () => []
        },
        fromDate: {
            type: Date,
            required: true
        },
        toDate: {
            type: Date,
            required: true
        },
        activeZoom: {
            type: String,
            default: 'Week'
        },
        selectedSettings: {
            type: Array,
            default: () => ['P', 'S', 'T','M']
        },
        projectList: {
            type: Array,
            default: () => []
        }
    },
    mounted() {
        this.setupScrollSynchronization();
    },
    beforeDestroy() {
        this.cleanupScrollSynchronization();
    },
    watch: {
        roadMapData() {
            this.$nextTick(() => {
                this.setupScrollSynchronization();
            });
        },
        activeZoom() {
            this.$nextTick(() => {
                this.setupScrollSynchronization();
            });
        }
    },
    methods:{
        HandlerEvent(projectId)
        {
            this.$parent.editProjectDetailHandler(projectId);
        },
        setupScrollSynchronization() {
            this.$nextTick(() => {
                // Find scroll containers - use multiple attempts to find them
                const resourcesContainer = document.querySelector('#resourcesmaindata');
                const sidebarContainer = document.querySelector('.sidebar-content') || 
                                       document.querySelector('aside.sidebar-content');
                const timePeriodContainer = document.querySelector('#time-periods') ||
                                          document.querySelector('.time-periods-container');
                
                if (!resourcesContainer) {
                    return;
                }
                
                if (!sidebarContainer) {
                    // Try again after a short delay if sidebar not found yet
                    setTimeout(() => {
                        this.setupScrollSynchronization();
                    }, 100);
                    return;
                }
                
                // Clean up existing listeners
                this.cleanupScrollSynchronization();
                
                // Store references
                this.scrollContainers = {
                    resources: resourcesContainer,
                    sidebar: sidebarContainer,
                    timePeriod: timePeriodContainer
                };
                
                // Ensure sidebar is scrollable
                if (sidebarContainer) {
                    const sidebarStyle = window.getComputedStyle(sidebarContainer);
                    if (sidebarStyle.overflowY === 'visible' || sidebarStyle.overflowY === 'hidden') {
                        sidebarContainer.style.overflowY = 'auto';
                    }
                }
                
                // Set up vertical scroll sync between Sidebar and Resources
                resourcesContainer.addEventListener('scroll', this.onResourcesScroll, { passive: true });
                sidebarContainer.addEventListener('scroll', this.onSidebarScroll, { passive: true });
                
                // Set up horizontal scroll sync between TimePeriod and Resources
                if (timePeriodContainer) {
                    resourcesContainer.addEventListener('scroll', this.onResourcesHorizontalScroll, { passive: true });
                    timePeriodContainer.addEventListener('scroll', this.onTimePeriodScroll, { passive: true });
                }
            });
        },
        onResourcesScroll(event) {
            // Sync vertical scroll from Resources to Sidebar
            if (this.isSyncingVertical) return;
            
            const resourcesContainer = this.scrollContainers?.resources;
            const sidebarContainer = this.scrollContainers?.sidebar;
            
            if (!resourcesContainer || !sidebarContainer) return;
            
            this.isSyncingVertical = true;
            const scrollTop = resourcesContainer.scrollTop;
            
            // Sync sidebar scroll position
            if (Math.abs(sidebarContainer.scrollTop - scrollTop) > 1) {
                sidebarContainer.scrollTop = scrollTop;
            }
            
            this.$nextTick(() => {
                this.isSyncingVertical = false;
            });
        },
        onSidebarScroll(event) {
            // Sync vertical scroll from Sidebar to Resources
            if (this.isSyncingVertical) return;
            
            const resourcesContainer = this.scrollContainers?.resources;
            const sidebarContainer = this.scrollContainers?.sidebar;
            
            if (!resourcesContainer || !sidebarContainer) return;
            
            this.isSyncingVertical = true;
            const scrollTop = sidebarContainer.scrollTop;
            
            if (resourcesContainer.scrollTop !== scrollTop) {
                resourcesContainer.scrollTop = scrollTop;
            }
            
            this.$nextTick(() => {
                this.isSyncingVertical = false;
            });
        },
        onResourcesHorizontalScroll(event) {
            // Sync horizontal scroll from Resources to TimePeriod
            if (this.isSyncingHorizontal) return;
            
            const resourcesContainer = this.scrollContainers?.resources;
            const timePeriodContainer = this.scrollContainers?.timePeriod;
            
            if (!resourcesContainer || !timePeriodContainer) return;
            
            this.isSyncingHorizontal = true;
            const scrollLeft = resourcesContainer.scrollLeft;
            
            if (timePeriodContainer.scrollLeft !== scrollLeft) {
                timePeriodContainer.scrollLeft = scrollLeft;
            }
            
            this.$nextTick(() => {
                this.isSyncingHorizontal = false;
            });
        },
        onTimePeriodScroll(event) {
            // Sync horizontal scroll from TimePeriod to Resources
            if (this.isSyncingHorizontal) return;
            
            const resourcesContainer = this.scrollContainers?.resources;
            const timePeriodContainer = this.scrollContainers?.timePeriod;
            
            if (!resourcesContainer || !timePeriodContainer) return;
            
            this.isSyncingHorizontal = true;
            const scrollLeft = timePeriodContainer.scrollLeft;
            
            if (resourcesContainer.scrollLeft !== scrollLeft) {
                resourcesContainer.scrollLeft = scrollLeft;
            }
            
            this.$nextTick(() => {
                this.isSyncingHorizontal = false;
            });
        },
        cleanupScrollSynchronization() {
            if (this.scrollContainers) {
                const { resources, sidebar, timePeriod } = this.scrollContainers;
                
                if (resources) {
                    resources.removeEventListener('scroll', this.onResourcesScroll);
                    resources.removeEventListener('scroll', this.onResourcesHorizontalScroll);
                }
                
                if (sidebar) {
                    sidebar.removeEventListener('scroll', this.onSidebarScroll);
                }
                
                if (timePeriod) {
                    timePeriod.removeEventListener('scroll', this.onTimePeriodScroll);
                }
            }
            
            this.scrollContainers = null;
        }
    },
    data() {
        return {
            scrollContainers: null,
            isSyncingVertical: false,
            isSyncingHorizontal: false
        };
    }
}
</script>
 
<style scoped>
.roadmap {
    position: relative;
    width: 100%;
}

#calendar.daily section.rm_cal{width: calc(100% - 240px)!important;}
</style>

